	"sort"
)

func solve(nums []int64) int64 {
	n := len(nums)
	if n == 0 {
		return 0
	}

	// Precompute all possible XOR values for subsets
	xorValues := make([]int64, 1<<n)
	for i := range xorValues {
		xor := int64(0)
		for j := 0; j < n; j++ {
			if i&(1<<j) != 0 {
				xor ^= nums[j]
			}
		}
		xorValues[i] = xor
	}

	// Precompute all possible AND values for subsets
	andValues := make([]int64, 1<<n)
	for i := range andValues {
		and := int64(0)
		for j := 0; j < n; j++ {
			if i&(1<<j) != 0 {
				if and == 0 {
					and = nums[j]
				} else {
					and &= nums[j]
				}
			}
		}
		andValues[i] = and
	}

	maxResult := int64(0)

	// Try all possible ways to split the array into three subsets
	for maskA := range xorValues {
		// Mask for subset A
		maskASet := make([]bool, n)
		for j := 0; j < n; j++ {
			if maskA&(1<<j) != 0 {
				maskASet[j] = true
			}
		}

		// Find the complement mask for B and C
		complementMask := ^maskA
		for j := 0; j < n; j++ {
			if (complementMask & (1<<j)) != 0 {
				maskASet[j] = false
			}
		}

		// Try all possible ways to split the complement into B and C
		for maskB := 0; maskB <= complementMask; maskB++ {
			// Mask for subset B
			maskBSet := make([]bool, n)
			for j := 0; j < n; j++ {
				if maskB&(1<<j) != 0 {
					maskBSet[j] = true
				}
			}

			// Mask for subset C is the complement of maskA and maskB
			maskC := ^maskA & ^maskB
			if maskC != 0 {
				// Check if all elements are assigned
				assigned := true
				for j := 0; j < n; j++ {
					if (maskA & (1<<j)) == 0 && (maskB & (1<<j)) == 0 && (maskC & (1<<j)) == 0 {
						assigned = false
						break
					}
				}
				if !assigned {
					continue
				}
			}

			// Calculate the result for this split
			result := xorValues[maskA]
			result += andValues[maskB]
			result += xorValues[maskC]
			if result > maxResult {
				maxResult = result
			}
		}
	}

	return maxResult
}
